import json
import pulumi_aws as aws

key = aws.kms.Key(
    "app-data",
    description="app data key",
    enable_key_rotation=True,
    deletion_window_in_days=7,
)

aws.kms.Alias("app-data-alias", name="alias/app-data", target_key_id=key.key_id)

use_policy = aws.iam.Policy(
    "use-app-data-key",
    policy=key.arn.apply(lambda arn: json.dumps({
        "Version": "2012-10-17",
        "Statement": [{
            "Effect": "Allow",
            "Action": ["kms:Encrypt", "kms:Decrypt", "kms:GenerateDataKey"],
            "Resource": arn,
        }],
    })),
)

import json
import pulumi_aws as aws

role = aws.iam.Role(
    "partner-readonly",
    assume_role_policy=json.dumps({
        "Version": "2012-10-17",
        "Statement": [{
            "Effect": "Allow",
            "Principal": {"AWS": "arn:aws:iam::444455556666:root"},
            "Action": "sts:AssumeRole",
            "Condition": {"StringEquals": {"sts:ExternalId": "unique-shared-secret"}},
        }],
    }),
)

aws.iam.RolePolicyAttachment(
    "partner-readonly-attach",
    role=role.name,
    policy_arn="arn:aws:iam::aws:policy/ReadOnlyAccess",
)
